question:
次のコードのループ本体（console.log）は何回実行されるか。

let i = 0;
while (i < 4) {
  console.log(i);
  i++;
}

次のコードで、最初に出力される値はいくつか。

let n = 10;
while (n > 0) {
  console.log(n);
  n -= 3;
}

次の do...while ループは何回実行されるか。

let x = 5;
do {
  console.log(x);
  x++;
} while (x < 3);

次のコードの出力として正しいものはどれか。

const day = 2;
switch (day) {
  case 1:
    console.log('月曜');
    break;
  case 2:
    console.log('火曜');
    break;
  case 3:
    console.log('水曜');
    break;
}

次のコードで出力される値を順番に答えるとき、正しいものはどれか。

let i = 1;
while (i <= 3) {
  console.log(i * 2);
  i++;
}

次のコードの出力として正しいものはどれか。

const score = 85;
switch (true) {
  case score >= 90:
    console.log('A');
    break;
  case score >= 80:
    console.log('B');
    break;
  default:
    console.log('C');
}

