次のコードで変数 count の最終的な値はいくつか。

let count = 0;
let i = 1;
while (i <= 10) {
  if (i % 3 === 0) {
    count++;
  }
  i++;
}
console.log(count);

次のコードの出力として正しいものはどれか。

let num = 1;
while (num <= 5) {
  if (num === 3) {
    num++;
    continue;
  }
  console.log(num);
  num++;
}

