let sum = 0;
let i = 1;
while (i <= 5) {
  sum += i;
  i++;
}
console.log(sum);

次のコードで getLabel(2) を呼び出したとき、戻り値として正しいものはどれか。

function getLabel(n) {
  switch (n) {
    case 1:
      return '一';
    case 2:
      return '二';
    case 3:
      return '三';
    default:
      return '不明';
  }
}

