次のコードで出力される最後の値はいくつか。

const arr = [3, 7, 2, 9, 4];
let i = 0;
let max = arr[0];
while (i < arr.length) {
  if (arr[i] > max) {
    max = arr[i];
  }
  i++;
}
console.log(max);

次のコードで calc('*', 3, 4) を呼び出したとき、戻り値として正しいものはどれか。

function calc(op, a, b) {
  switch (op) {
    case '+':
      return a + b;
    case '-':
      return a - b;
    case '*':
      return a * b;
    case '/':
      return b !== 0 ? a / b : 'エラー';
    default:
      return '演算子が不明';
  }
}

次のコードで変数 found の最終的な値として正しいものはどれか。

const target = 7;
const arr = [2, 5, 7, 11, 13];
let i = 0;
let found = false;
while (i < arr.length) {
  if (arr[i] === target) {
    found = true;
    break;
  }
  i++;
}
console.log(found);

次のコードで変数 output の値として正しいものはどれか。

let output = '';
let i = 1;
while (i <= 6) {
  switch (i % 3) {
    case 0:
      output += 'C';
      break;
    case 1:
      output += 'A';
      break;
    case 2:
      output += 'B';
      break;
  }
  i++;
}
console.log(output);
